protected TextWidget m_wLabel;
protected string m_sDisplayText;

void SetLabelWidget(Widget root)
{
  m_wLabel = TextWidget.Cast(root.FindAnyWidget("ValueText"));
}

override void EOnInit(IEntity owner)
{
  SetEventMask(owner, EntityEvent.FRAME);
}

override void EOnFrame(IEntity owner, float timeSlice)
{
  if (m_wLabel)
    m_wLabel.SetTextFormat(m_sDisplayText);
}
